consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
.breadcrumb {
  display: flex;
  align-items: center;
}

.list {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: var(--dimension-space-050);
}

.item {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
}

.link {
  color: var(--color-foreground-secondary);
  text-decoration: none;
  background: none;
  border: none;
  padding: var(--dimension-space-025) var(--dimension-space-050);
  border-radius: var(--dimension-radius-050);
  cursor: pointer;
  transition: background-color var(--effect-motion-short-2), color var(--effect-motion-short-2);
}

.link:hover {
  background-color: var(--color-interaction-hover);
  color: var(--color-foreground-primary);
}

.link:active {
  background-color: var(--color-interaction-pressed);
}

.separator {
  color: var(--color-foreground-tertiary);
  font-size: 12px;
  -webkit-user-select: none;
  user-select: none;
}

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import { Text } from '@/components/Text';
import styles from './Breadcrumb.module.css';

export interface BreadcrumbItem {
  label: string;
  href?: string;
  onClick?: () => void;
}

export interface BreadcrumbProps {
  /** Ordered list of breadcrumb items. Last item is treated as current page. */
  items: BreadcrumbItem[];
  /** Custom separator. Defaults to '/'. */
  separator?: React.ReactNode;
  className?: string;
}

export const Breadcrumb = forwardRef<HTMLElement, BreadcrumbProps>(
  ({ items, separator = '/', className }, ref) => (
    <nav ref={ref} aria-label="Breadcrumb" className={cn(styles.breadcrumb, className)}>
      <ol className={styles.list}>
        {items.map((item, i) => {
          const isLast = i === items.length - 1;
          return (
            <li key={i} className={styles.item}>
              {isLast ? (
                <Text variant="text-body-medium-emphasis" as="span" color="primary" aria-current="page">
                  {item.label}
                </Text>
              ) : (
                <>
                  {item.href ? (
                    <a
                      href={item.href}
                      className={styles.link}
                      onClick={e => { if (item.onClick) { e.preventDefault(); item.onClick(); } }}
                    >
                      <Text variant="text-body-medium" as="span" color="inherit">
                        {item.label}
                      </Text>
                    </a>
                  ) : (
                    <button
                      type="button"
                      className={styles.link}
                      onClick={item.onClick}
                    >
                      <Text variant="text-body-medium" as="span" color="inherit">
                        {item.label}
                      </Text>
                    </button>
                  )}
                  <span className={styles.separator} aria-hidden="true">
                    {separator}
                  </span>
                </>
              )}
            </li>
          );
        })}
      </ol>
    </nav>
  )
);

Breadcrumb.displayName = 'Breadcrumb';
